1	//! Direct expansion checks (AST-level). Each fixture mirrors a `[Qn]` oracle
2	//! observation and, for the byte-parity set, the hand-inlined `.spthy` in
3	//! ../fixtures/ that workspace/byteparity.sh proves equal to the macro theory.
4	
5	use super::ast::*;
6	use super::{expand, expand_staged};
7	
8	// ---- tiny AST constructors ------------------------------------------------
9	
10	fn var(name: &str, sort: SortHint) -> VarSpec {
11	    VarSpec { name: name.into(), idx: 0, sort, typ: None }
12	}
13	fn msg(name: &str) -> Term {
14	    Term::Var(var(name, SortHint::Untagged))
15	}
16	fn fresh(name: &str) -> Term {
17	    Term::Var(var(name, SortHint::Fresh))
18	}
19	fn pubv(name: &str) -> Term {
20	    Term::Var(var(name, SortHint::Pub))
21	}
22	fn pair(ts: Vec<Term>) -> Term {
23	    Term::Pair(ts)
24	}
25	fn app(name: &str, args: Vec<Term>) -> Term {
26	    Term::App(name.into(), args)
27	}
28	fn fact(name: &str, args: Vec<Term>) -> Fact {
29	    Fact { persistent: false, name: name.into(), args, annotations: vec![] }
30	}
31	fn mdef(name: &str, formals: &[VarSpec], body: Term) -> Macro {
32	    Macro { name: name.into(), args: formals.to_vec(), body }
33	}
34	/// A minimal rule with one action fact `Act(<action_arg>)`.
35	fn rule_act(name: &str, prems: Vec<Fact>, action: Fact) -> Rule {
36	    Rule {
37	        name: name.into(),
38	        modulo: None,
39	        attributes: vec![],
40	        let_block: vec![],
41	        premises: prems,
42	        actions: vec![action],
43	        conclusions: vec![],
44	        embedded_restrictions: vec![],
45	        variants: vec![],
46	        left_right: None,
47	    }
48	}
49	fn theory(items: Vec<TheoryItem>) -> Theory {
50	    Theory { is_diff: false, name: "T".into(), configuration: None, items }
51	}
52	
53	/// The action term of the single rule in a single-rule theory (post-expand).
54	fn only_rule_action_arg(t: &Theory) -> Term {
55	    let r = t.items.iter().find_map(|it| match it {
56	        TheoryItem::Rule(r) => Some(r),
57	        _ => None,
58	    }).expect("a rule");
59	    r.actions[0].args[0].clone()
60	}
