62	// ---- macros: declarations are preserved in place [Q37] --------------------
63	
64	#[test]
65	fn preserves_macro_declarations() {
66	    // The `macros:` block is retained in place (with its original, unexpanded
67	    // body) while the use site is expanded. The consuming pipeline requires the
68	    // declaration block, and the reference retains it in its pretty output.
69	    let x = var("x", SortHint::Untagged);
70	    let macros = TheoryItem::Macros(vec![mdef("m", &[x.clone()], msg("x"))]);
71	    let t = theory(vec![
72	        macros.clone(),
73	        TheoryItem::Rule(rule_act("R", vec![fact("In", vec![msg("x")])],
74	                                  fact("Act", vec![app("m", vec![msg("x")])]))),
75	    ]);
76	    let out = expand(&t);
77	    // declaration item retained, unchanged, in its original position
78	    assert_eq!(out.items.len(), 2);
79	    assert_eq!(out.items[0], macros);
80	    // use site expanded: Act(m(x)) -> Act(x)
81	    assert_eq!(only_rule_action_arg(&out), msg("x"));
82	}
