86	#[test]
87	fn capture_simultaneous_substitution() {
88	    // swap(x,y) = <x,y>;  Act(swap(y,x))  ==>  Act(<y,x>)
89	    let (x, y) = (var("x", SortHint::Untagged), var("y", SortHint::Untagged));
90	    let t = theory(vec![
91	        TheoryItem::Macros(vec![mdef("swap", &[x.clone(), y.clone()],
92	                                     pair(vec![msg("x"), msg("y")]))]),
93	        TheoryItem::Rule(rule_act(
94	            "R",
95	            vec![fact("In", vec![msg("x")]), fact("In", vec![msg("y")])],
96	            fact("Act", vec![app("swap", vec![msg("y"), msg("x")])]),
97	        )),
98	    ]);
99	    assert_eq!(only_rule_action_arg(&expand(&t)), pair(vec![msg("y"), msg("x")]));
100	    // A sequential (buggy) substitution would give <x,x> or <y,y>.
101	    assert_ne!(only_rule_action_arg(&expand(&t)), pair(vec![msg("x"), msg("x")]));
102	    assert_ne!(only_rule_action_arg(&expand(&t)), pair(vec![msg("y"), msg("y")]));
103	}
