238	#[test]
239	fn sort_sensitive_matching() {
240	    // m(x) = ~x ;  n(x) = x
241	    // M(m(a)) ==> M(~x)   (formal x[Untagged] != body ~x[Fresh]; arg a dropped)
242	    // N(n(~b)) ==> N(~b)  (formal x matches body x; arg ~b substituted)
243	    let x = var("x", SortHint::Untagged);
244	    let macros = TheoryItem::Macros(vec![
245	        mdef("m", &[x.clone()], fresh("x")),
246	        mdef("n", &[x.clone()], msg("x")),
247	    ]);
248	    let r = Rule {
249	        name: "R".into(), modulo: None, attributes: vec![], let_block: vec![],
250	        premises: vec![fact("In", vec![msg("a")]), fact("Fr", vec![fresh("b")])],
251	        actions: vec![
252	            fact("M", vec![app("m", vec![msg("a")])]),
253	            fact("N", vec![app("n", vec![fresh("b")])]),
254	        ],
255	        conclusions: vec![], embedded_restrictions: vec![], variants: vec![], left_right: None,
256	    };
257	    let out = expand(&theory(vec![macros, TheoryItem::Rule(r)]));
258	    let acts = match out.items.iter().find_map(|it| match it {
259	        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap() {
260	        r => r.actions.clone(),
261	    };
262	    assert_eq!(acts[0], fact("M", vec![fresh("x")]));   // ~x survives, a dropped
263	    assert_eq!(acts[1], fact("N", vec![fresh("b")]));   // ~b substituted for x
264	}
