562	// ===========================================================================
563	// ROUND 5 — staged (parse-stage) mode: `expand_staged`
564	//
565	// The consumer's pipeline calls `expand_staged` at a stage where a later stage
566	// owns acc-lemma & case-test expansion [Q41] and rules exist only in their
567	// primary form [Q42]. So `expand_staged` leaves acc-lemma / case-test formulas
568	// and derived variant / left-right rule forms UNTOUCHED, while still fully
569	// expanding ordinary lemmas / restrictions / the primary rule form and resolving
570	// bare-nullary uses. Full close (`expand`) stays unchanged (its behaviour is
571	// pinned by every test above).
572	// ===========================================================================
573	
574	/// A one-restriction/one-lemma/one-rule + acc-lemma + case-test + bare-nullary
575	/// theory exercising every staged carve-out at once.
576	fn staged_mixed_theory() -> (Theory, TheoryItem) {
577	    let x = var("x", SortHint::Untagged);
578	    let macros = TheoryItem::Macros(vec![
579	        mdef("m", &[x.clone()], pair(vec![msg("x"), msg("x")])),
580	        mdef("konst", &[], app("h", vec![publit("k")])),
581	    ]);
582	    // ordinary rule (primary form): [In(x)] --[A(m(x))]-> [Out(konst)]
583	    let r = Rule {
584	        name: "R".into(), modulo: None, attributes: vec![], let_block: vec![],
585	        premises: vec![fact("In", vec![msg("x")])],
586	        actions: vec![fact("A", vec![app("m", vec![msg("x")])])],
587	        conclusions: vec![fact("Out", vec![msg("konst")])], // bare-nullary use
588	        embedded_restrictions: vec![], variants: vec![], left_right: None,
589	    };
590	    // ordinary restriction: All x #i. A(m(x))@i ==> Ex y. x=y
591	    let y = var("y", SortHint::Untagged);
592	    let restr = TheoryItem::Restriction(Restriction {
593	        name: "Restr".into(), attributes: vec![],
594	        formula: Formula::Forall(
595	            vec![x.clone(), var("i", SortHint::Node)],
596	            Box::new(Formula::Implies(
597	                Box::new(Formula::Atom(Atom::Action(
598	                    fact("A", vec![app("m", vec![msg("x")])]),
599	                    Term::Var(var("i", SortHint::Node)),
600	                ))),
601	                Box::new(Formula::Exists(vec![y.clone()],
602	                    Box::new(Formula::Atom(Atom::Eq(msg("x"), msg("y")))))),
603	            )),
604	        ),
605	    });
606	    // ordinary lemma: exists-trace Ex x #i. A(m(x))@i
607	    let lem = TheoryItem::Lemma(Lemma {
608	        name: "L".into(), modulo: None, attributes: vec![],
609	        trace_quantifier: TraceQuantifier::ExistsTrace,
610	        formula: exists_action("A", app("m", vec![msg("sid")])),
611	        proof: None, plaintext: String::new(),
612	    });
613	    // acc-lemma & case-test both use the macro in their formula
614	    let acc = TheoryItem::AccLemma(AccLemma {
615	        name: "acc".into(), attributes: vec![],
616	        formula: exists_action("Unequal", app("m", vec![msg("sid")])),
617	        case_test_idents: vec!["blamed".into()],
618	    });
619	    let ctest = TheoryItem::CaseTest(CaseTest {
620	        name: "blamed".into(),
621	        formula: exists_action("Blame", app("m", vec![msg("sid")])),
622	    });
623	    let t = theory(vec![
624	        macros.clone(), TheoryItem::Rule(r), restr, lem, acc, ctest,
625	    ]);
626	    (t, macros)
627	}
