629	// ---- acc-lemma & case-test formulas are byte-identical through staged mode --
630	
631	#[test]
632	fn staged_leaves_acc_and_case_test_untouched() {
633	    let (t, _) = staged_mixed_theory();
634	    let out = expand_staged(&t);
635	    // The acc-lemma and case-test items are byte-identical to their inputs
636	    // (whole item unchanged, macro call preserved).
637	    let acc_in = t.items.iter().find(|it| matches!(it, TheoryItem::AccLemma(_))).unwrap();
638	    let ct_in = t.items.iter().find(|it| matches!(it, TheoryItem::CaseTest(_))).unwrap();
639	    let acc_out = out.items.iter().find(|it| matches!(it, TheoryItem::AccLemma(_))).unwrap();
640	    let ct_out = out.items.iter().find(|it| matches!(it, TheoryItem::CaseTest(_))).unwrap();
641	    assert_eq!(acc_out, acc_in);
642	    assert_eq!(ct_out, ct_in);
643	    // Concretely: the macro call still stands, un-expanded, in both formulas.
644	    assert_eq!(
645	        match acc_out { TheoryItem::AccLemma(a) => a.formula.clone(), _ => unreachable!() },
646	        exists_action("Unequal", app("m", vec![msg("sid")])),
647	    );
648	    assert_eq!(
649	        match ct_out { TheoryItem::CaseTest(c) => c.formula.clone(), _ => unreachable!() },
650	        exists_action("Blame", app("m", vec![msg("sid")])),
651	    );
652	}
