663	// ---- ordinary lemmas / restrictions / (primary) rules still fully expand ----
664	
665	#[test]
666	fn staged_expands_ordinary_lemma_restriction_rule() {
667	    let (t, _) = staged_mixed_theory();
668	    let out = expand_staged(&t);
669	
670	    // primary rule form expanded: A(m(x)) -> A(<x,x>)
671	    let r = out.items.iter().find_map(|it| match it {
672	        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap();
673	    assert_eq!(r.actions[0], fact("A", vec![pair(vec![msg("x"), msg("x")])]));
674	
675	    // restriction formula expanded
676	    let restr = out.items.iter().find_map(|it| match it {
677	        TheoryItem::Restriction(r) => Some(r), _ => None }).unwrap();
678	    let expected_restr = Formula::Forall(
679	        vec![var("x", SortHint::Untagged), var("i", SortHint::Node)],
680	        Box::new(Formula::Implies(
681	            Box::new(Formula::Atom(Atom::Action(
682	                fact("A", vec![pair(vec![msg("x"), msg("x")])]),
683	                Term::Var(var("i", SortHint::Node)),
684	            ))),
685	            Box::new(Formula::Exists(vec![var("y", SortHint::Untagged)],
686	                Box::new(Formula::Atom(Atom::Eq(msg("x"), msg("y")))))),
687	        )),
688	    );
689	    assert_eq!(restr.formula, expected_restr);
690	
691	    // ordinary lemma formula expanded
692	    let lem = out.items.iter().find_map(|it| match it {
693	        TheoryItem::Lemma(l) => Some(l), _ => None }).unwrap();
694	    assert_eq!(lem.formula, exists_action("A", pair(vec![msg("sid"), msg("sid")])));
695	}
696	
697	// ---- bare-nullary resolution is still active in staged mode -----------------
698	
699	#[test]
700	fn staged_bare_nullary_still_resolves() {
701	    let (t, _) = staged_mixed_theory();
702	    let out = expand_staged(&t);
703	    let r = out.items.iter().find_map(|it| match it {
704	        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap();
705	    // Out(konst) -> Out(h('k'))
706	    assert_eq!(r.conclusions[0], fact("Out", vec![app("h", vec![publit("k")])]));
707	}
