709	// ---- staged mode touches ONLY the primary rule form, not derived variants ---
710	
711	#[test]
712	fn staged_does_not_recurse_into_rule_variants() {
713	    // A rule carrying a `(modulo AC)` variant (and a left/right diff form), each
714	    // holding a macro call. Staged mode expands the primary form but leaves the
715	    // derived forms verbatim [Q42]; full close expands all of them.
716	    let x = var("x", SortHint::Untagged);
717	    let macros = TheoryItem::Macros(vec![mdef("m", &[x.clone()], pair(vec![msg("x"), msg("x")]))]);
718	    let variant = rule_act("R", vec![], fact("A", vec![app("m", vec![msg("v")])]));
719	    let lr_side = rule_act("R", vec![], fact("A", vec![app("m", vec![msg("l")])]));
720	    let primary = Rule {
721	        name: "R".into(), modulo: None, attributes: vec![], let_block: vec![],
722	        premises: vec![], actions: vec![fact("A", vec![app("m", vec![msg("p")])])],
723	        conclusions: vec![], embedded_restrictions: vec![],
724	        variants: vec![variant.clone()],
725	        left_right: Some((Box::new(lr_side.clone()), Box::new(lr_side.clone()))),
726	    };
727	    let t = theory(vec![macros, TheoryItem::Rule(primary)]);
728	
729	    // staged: primary expanded, variant + left/right untouched.
730	    let staged = expand_staged(&t);
731	    let sr = staged.items.iter().find_map(|it| match it {
732	        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap();
733	    assert_eq!(sr.actions[0], fact("A", vec![pair(vec![msg("p"), msg("p")])])); // primary expanded
734	    assert_eq!(sr.variants, vec![variant.clone()]);                             // variant verbatim
735	    assert_eq!(
736	        sr.left_right,
737	        Some((Box::new(lr_side.clone()), Box::new(lr_side.clone()))),           // diff form verbatim
738	    );
739	
740	    // full close: every form expanded (contrast — pins the mode difference).
741	    let full = expand(&t);
742	    let fr = full.items.iter().find_map(|it| match it {
743	        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap();
744	    assert_eq!(fr.actions[0], fact("A", vec![pair(vec![msg("p"), msg("p")])]));
745	    assert_eq!(fr.variants[0].actions[0], fact("A", vec![pair(vec![msg("v"), msg("v")])]));
746	    let (fl, _) = fr.left_right.as_ref().unwrap();
747	    assert_eq!(fl.actions[0], fact("A", vec![pair(vec![msg("l"), msg("l")])]));
748	}
